{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CODE_STYLE_PROPERTY
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleValue
import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

class FunctionSignatureRuleReproductionTest {
    private val functionSignatureRuleAssertThat = assertThatRule { FunctionSignatureRule() }

    @Test
    fun `Do not merge annotated expression with function signature`() {
        val code =
            """
            private fun getErrorMessage(value: String): String =
                @Suppress("DEPRECATION")
                customMessage.takeUnless { it.isEmpty() } ?: String.format(DEFAULT_ERROR_MESSAGE_WITH_NO_REASON, value)
            """.trimIndent()
        // The rule should NOT want to merge the expression with the signature if it starts with an annotation
        functionSignatureRuleAssertThat(code)
            .withEditorConfigValue(CODE_STYLE_PROPERTY, CodeStyleValue.android)
            .hasNoLintViolations()
    }
}
